import psycopg2
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/query', methods=['POST'])
def query():
    table_name = request.json['table_name']
    column_names = request.json['column_names']
    filter_conditions = request.json['filter_conditions']

    # Build SQL query dynamically based on user input
    sql = f"SELECT {', '.join(column_names)} FROM {table_name} WHERE {' AND '.join(filter_conditions)}"

    # Connect to PostgreSQL database
    conn = psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )

    # Execute SQL query
    cur = conn.cursor()
    cur.execute(sql)

    # Fetch results
    results = cur.fetchall()

    # Close connection
    cur.close()
    conn.close()

    return jsonify(results)